package be.schaubroeck.lpb.rkm.rekenmotor.util;

import be.schaubroeck.lpb.rkm.rekenmotor.planningsuren.UitzonderlijkPerUur;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.NlpPrestatie;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.enumtypes.AardKodeExt;
import be.schaubroeck.lpb.tools.enumtypes.Tellerkode;
import lombok.AllArgsConstructor;

@AllArgsConstructor
public class PrestatieSamenvattingUitzPerUur extends AbstractPrestatieSamenvatting {

    private final UitzonderlijkPerUur uitzonderlijkPerUur;
    private final Opdracht opdracht;
    private final boolean bezoldigdePrestatiesAanwezigUitzPerUur;

    @Override
    public void verwerk(NlpPrestatie prestatie, AardKodeExtensie looncode) {
        Tellerkode tellerCode = looncode.getTellerCode();
        if (gebruikTellerCodeGewoonLoon(looncode)) {
            tellerCode = Tellerkode.GW;
        } else if (gebruikTellerCodeOnbezoldigd(looncode)) {
            tellerCode = Tellerkode.ONB;
        }
        super.verwerk(prestatie.getAantal(), looncode, tellerCode);
    }

    private boolean gebruikTellerCodeGewoonLoon(AardKodeExtensie looncode) {
        return bezoldigdePrestatiesAanwezigUitzPerUur && (isKalenderCode(looncode) ||
                (looncode.getTellerCode() == Tellerkode.ONB && uitzonderlijkPerUur.isLangdurigeAfwezigheid(opdracht, looncode.getCode(), looncode.getExtensie())));
    }

    private boolean isKalenderCode(AardKodeExtensie looncode) {
        return looncode.getAard().equals(AardKodeExt.K_KODE_EXT.getCode());
    }

    private boolean gebruikTellerCodeOnbezoldigd(AardKodeExtensie looncode) {
        return !bezoldigdePrestatiesAanwezigUitzPerUur && looncode.getTellerCode() == Tellerkode.GW &&
                uitzonderlijkPerUur.isLangdurigeAfwezigheid(opdracht, looncode.getCode(), looncode.getExtensie());
    }

    @Override
    public PrestatieSamenvattingUitzPerUur addPrestatieSamenvatting(PrestatieSamenvatting other) {
        return addPrestatieSamenvatting(other, this);
    }
}
